// DATA COLLECTOR — Aggregate all signals
const revenue = $('Read Revenue').all();
const content = $('Read Content Performance').all();
const patterns = $('Read Winning Patterns').all();

// Revenue metrics
const totalCustomers = revenue.length;
const totalRevenue = totalCustomers * 350;
const target = 28;
const remaining = target - totalCustomers;

// Content metrics
const totalVideos = content.length;
const avgScore = content.length > 0 
  ? content.reduce((sum, c) => sum + (c.json.performance_score || 0), 0) / content.length 
  : 0;
const topVideos = content.filter(c => (c.json.performance_score || 0) >= 70).length;
const deadVideos = content.filter(c => (c.json.performance_score || 0) <= 30).length;

// DM metrics
const totalDMs = content.reduce((sum, c) => sum + (c.json.dms_generated || 0), 0);
const conversionRate = totalDMs > 0 ? (totalCustomers / totalDMs * 100).toFixed(1) : 0;

// Patterns
const scalePatterns = patterns.filter(p => p.json.result === 'SCALE').length;
const killPatterns = patterns.filter(p => p.json.result === 'KILL').length;
const winRate = patterns.length > 0 
  ? (scalePatterns / patterns.length * 100).toFixed(1) 
  : 0;

// Deadline
const deadline = new Date('2026-04-05T23:59:59');
const now = new Date();
const hoursLeft = Math.max(0, Math.round((deadline - now) / (1000 * 60 * 60)));
const daysLeft = Math.round(hoursLeft / 24);

// Velocity
const customersPerDay = daysLeft > 0 ? (remaining / daysLeft).toFixed(1) : remaining;

return {
  json: {
    revenue: { totalCustomers, totalRevenue, remaining, target },
    content: { totalVideos, avgScore: Math.round(avgScore), topVideos, deadVideos },
    dms: { totalDMs, conversionRate },
    patterns: { scalePatterns, killPatterns, winRate },
    time: { hoursLeft, daysLeft, customersPerDay }
  }
};

// DYNAMIC PRICING ENGINE
const data = $input.item.json;
const { revenue, dms, time } = data;

const currentPrice = 350;
const basePrice = 820;
let recommendedPrice = currentPrice;
let pricingAction = '';
let urgencyLevel = '';

// High demand + High conversion → Price UP
if (parseFloat(dms.conversionRate) > 15 && revenue.remaining > 10) {
  recommendedPrice = 450;
  pricingAction = 'رفع السعر إلى 450 — الطلب عالي والتحويل ممتاز';
  urgencyLevel = 'PRICE_UP';
}
// Very high demand → Premium pricing
else if (parseFloat(dms.conversionRate) > 25) {
  recommendedPrice = 550;
  pricingAction = 'رفع السعر إلى 550 — الطلب استثنائي';
  urgencyLevel = 'PRICE_UP';
}
// Low demand → Flash sale
else if (dms.totalDMs < 20 && time.daysLeft <= 3) {
  recommendedPrice = 280;
  pricingAction = 'تخفيض مؤقت 280 — آخر 3 أيام + الطلب منخفض';
  urgencyLevel = 'FLASH_SALE';
}
// Medium demand → Add scarcity
else if (parseFloat(dms.conversionRate) < 5 && dms.totalDMs > 30) {
  recommendedPrice = currentPrice;
  pricingAction = 'السعر ثابت + فعّل Scarcity (باقي 5 مقاعد فقط)';
  urgencyLevel = 'ADD_SCARCITY';
}
// Normal → Keep price
else {
  pricingAction = 'السعر مناسب — استمر';
  urgencyLevel = 'STABLE';
}

// Scarcity message
let scarcityMsg = '';
if (time.daysLeft <= 2) {
  scarcityMsg = `⏰ العرض ينتهي خلال ${time.daysLeft} يوم فقط!`;
} else if (revenue.remaining <= 10) {
  scarcityMsg = `🔥 باقي ${revenue.remaining} مقعد فقط!`;
}

return {
  json: {
    ...data,
    pricing: {
      current: currentPrice,
      recommended: recommendedPrice,
      action: pricingAction,
      urgency: urgencyLevel,
      scarcity: scarcityMsg
    }
  }
};

// PREDICTIVE SCALING ENGINE
const data = $input.item.json;
const { revenue, content, dms, patterns, time, pricing } = data;

let predictions = [];
let actions = [];

// Prediction 1: Content velocity
if (content.totalVideos < 5 && time.daysLeft > 1) {
  predictions.push('⚠️ الإنتاج بطيء — لن نصل للهدف بالمعدل الحالي');
  actions.push('🎬 ضاعف الإنتاج: 10+ فيديو اليوم');
}

// Prediction 2: DM drought
if (dms.totalDMs < 15 && content.totalVideos > 5) {
  predictions.push('📉 المحتوى لا يولّد تفاعل — Hook ضعيف');
  actions.push('🐺 ذئب الشمال: جدد الـ Hooks فوراً');
}

// Prediction 3: Conversion bottleneck
if (dms.totalDMs > 30 && parseFloat(dms.conversionRate) < 5) {
  predictions.push('🔴 عندنا leads لكن ما ينغلقوا — مشكلة إغلاق');
  actions.push('🌹 وردة: ركزي على Interest → Close مباشرة');
}

// Prediction 4: Winning pattern available
if (parseFloat(patterns.winRate) > 60 && content.topVideos > 0) {
  predictions.push('🟢 عندنا Pattern ناجح — وقت المضاعفة');
  actions.push('🔥 Scale: أنتج 5 نسخ من أفضل فيديو');
}

// Prediction 5: Time pressure
if (time.daysLeft <= 2 && revenue.remaining > 15) {
  predictions.push('🚨 وقت ضيق + هدف بعيد — يلزم إجراء عاجل');
  actions.push('⚡ فعّل وضع الطوارئ: كل الموارد على الإغلاق');
}

// Prediction 6: Almost there
if (revenue.remaining <= 5 && revenue.remaining > 0) {
  predictions.push('🎯 قريبين جداً من الهدف!');
  actions.push('💪 Push أخير: تواصل مباشر مع كل Lead مفتوح');
}

// Overall strategy
let overallStrategy = '';
if (actions.length === 0) {
  overallStrategy = '✅ النظام يعمل بشكل جيد — استمر';
  actions.push('📊 راقب وكرر اللي يشتغل');
} else {
  overallStrategy = `⚠️ ${predictions.length} تنبيهات — تدخل مطلوب`;
}

return {
  json: {
    ...data,
    brain: {
      predictions,
      actions,
      overallStrategy,
      timestamp: new Date().toISOString()
    }
  }
};

